pipeline.evaluate:
(async () => {
  const id = '${{ args.id }}';
  const limit = ${{ args.limit }};
  const url = `https://www.xiaoyuzhoufm.com/podcast/${id}`;
  const resp = await fetch(url, {
    headers: { 'User-Agent': 'Mozilla/5.0 (compatible; agent-browser-hub)' }
  });
  if (!resp.ok) throw new Error(`HTTP ${resp.status} for podcast/${id}`);
  const html = await resp.text();
  const match = html.match(/<script id="__NEXT_DATA__"[^>]*>([\s\S]*?)<\/script>/);
  if (!match) throw new Error('Failed to extract __NEXT_DATA__');
  const parsed = JSON.parse(match[1]);
  const podcast = parsed.props?.pageProps?.podcast;
  if (!podcast) throw new Error('Podcast not found');
  const allEpisodes = podcast.episodes || [];
  const formatDuration = (sec) => {
    if (!Number.isFinite(sec) || sec < 0) return '-';
    sec = Math.round(sec);
    const m = Math.floor(sec / 60);
    const s = sec % 60;
    return `${m}:${String(s).padStart(2, '0')}`;
  };
  return allEpisodes.slice(0, Math.min(limit, allEpisodes.length)).map(ep => ({
    eid: ep.eid,
    title: ep.title,
    duration: formatDuration(ep.duration),
    plays: ep.playCount,
    date: (ep.pubDate || '').slice(0, 10)
  }));
})()
